import { DEFAULT_LANGUAGE, normalizeLanguage } from '../utils/i18n.js';

const FAQ_CONTENT = {
  en: [
    { id: 'q1', category: 'General', question: 'What is SimpleTool and who is it for?', answer: 'SimpleTool is a privacy-first set of browser-based utilities for developers, operators, and power users. Tasks like formatting JSON, decoding tokens, or generating credentials run locally in the browser instead of on our servers.' },
    { id: 'q2', category: 'General', question: 'Is SimpleTool really free?', answer: 'Yes. The public site is free to use, with advertising helping cover hosting and maintenance. There are no paid tiers required to access the core tools.' },
    { id: 'q3', category: 'General', question: 'Do I need to create an account?', answer: 'No. You can open a tool and use it immediately without creating an account or logging in.' },
    { id: 'q4', category: 'General', question: 'Is my data safe? How does client-side processing work?', answer: 'For most tools, processing happens locally in your browser using JavaScript and browser APIs. That means the input usually stays on your device unless you explicitly copy, export, or send it elsewhere.' },
    { id: 'q5', category: 'General', question: 'Which browsers are supported?', answer: 'SimpleTool supports modern versions of Chrome, Edge, Firefox, and Safari, plus up-to-date mobile browsers. Older browsers without ES modules or Web Crypto support may not work correctly.' },
    { id: 'q6', category: 'General', question: 'Can I use SimpleTool offline?', answer: 'Many tools continue working after the page loads because the logic runs client-side. For a dependable offline workflow, self-hosting the project is the safest option.' },
    { id: 'q7', category: 'Security & Cryptography', question: 'What makes a password truly secure?', answer: 'A secure password is long, random, and unique per service. Length and unpredictability matter more than clever substitutions or memorable patterns.' },
    { id: 'q8', category: 'Security & Cryptography', question: "What's the difference between MD5, SHA-256, and SHA-512?", answer: 'MD5 is obsolete for security. SHA-256 and SHA-512 are modern SHA-2 hashes; SHA-512 has a larger output, while SHA-256 is the common default for integrity and signing workflows.' },
    { id: 'q9', category: 'Security & Cryptography', question: 'Why is MD5 considered broken?', answer: 'MD5 is vulnerable to practical collision attacks, so two different inputs can be crafted to produce the same hash. That makes it unsuitable for trust, signatures, or password storage.' },
    { id: 'q10', category: 'Security & Cryptography', question: 'What is HMAC and when should I use it?', answer: 'HMAC combines a hash function with a shared secret key. Use it when you need both integrity and authenticity, such as signed API requests or webhook verification.' },
    { id: 'q11', category: 'Security & Cryptography', question: 'How does bcrypt compare to Argon2 for password hashing?', answer: 'Both are purpose-built password hashing algorithms, but Argon2 is the more modern choice because it is memory-hard and easier to tune against GPU attacks. bcrypt remains common for compatibility.' },
    { id: 'q12', category: 'Security & Cryptography', question: 'What is a JWT and when should I use one?', answer: 'A JWT is a compact token format for carrying claims between systems. It is useful for stateless authentication and service-to-service identity, but only when signatures, expiration, and validation are handled correctly.' },
    { id: 'q13', category: 'Security & Cryptography', question: "How do I verify a file's integrity using hash checksums?", answer: 'Compute the file hash locally and compare it with the official value from the publisher. If the hashes match exactly, the file is very likely unchanged.' },
    { id: 'q14', category: 'Security & Cryptography', question: 'What is Content Security Policy (CSP) and why does it matter?', answer: 'CSP is a browser-enforced security policy that restricts where scripts, styles, images, and other resources can come from. It is one of the strongest defenses against XSS and injected content.' },
    { id: 'q15', category: 'Data Formats', question: "What's the difference between JSON and YAML?", answer: 'JSON is stricter, more predictable, and usually better for APIs and machine exchange. YAML is easier for humans to edit, but indentation and advanced syntax can introduce hidden mistakes.' },
    { id: 'q16', category: 'Data Formats', question: 'How do I validate JSON?', answer: 'First check that the syntax is valid, then validate the structure against a schema if the data must follow a contract. Syntax validation alone does not guarantee the right fields or types.' },
    { id: 'q17', category: 'Data Formats', question: 'What is Base64 encoding and when is it used?', answer: 'Base64 is a text-safe encoding for binary data. It is commonly used in tokens, email payloads, data URLs, and transport formats that require plain text.' },
    { id: 'q18', category: 'Data Formats', question: 'What are regular expressions and why are they useful?', answer: 'Regular expressions are compact patterns for matching and transforming text. They are useful for validation, extraction, search, and cleanup, but they should be written carefully to avoid complexity and performance problems.' },
    { id: 'q19', category: 'Data Formats', question: 'How do I convert between different timestamp formats?', answer: 'Normalize the source into a clear reference such as Unix seconds, Unix milliseconds, or ISO 8601, then render it in the target format and timezone. Most timestamp bugs come from timezone and unit mismatches.' },
    { id: 'q20', category: 'Data Formats', question: 'What is a UUID and when should I use one?', answer: 'A UUID is a globally unique identifier that can be generated without a central database. It is useful for distributed systems, test data, and identifiers that should not be easy to enumerate.' },
    { id: 'q21', category: 'Data Formats', question: 'What is JSON Schema and why should I use it?', answer: 'JSON Schema defines the allowed structure, types, and rules for JSON documents. It helps keep APIs, events, and configuration files consistent and testable.' },
    { id: 'q22', category: 'Data Formats', question: 'How do I compare two text files for differences?', answer: 'Use a diff tool that highlights added, removed, and changed sections side by side. A visual diff is faster and safer than manually scanning large files.' },
    { id: 'q23', category: 'Networking & Web', question: 'How do CIDR subnets and IP ranges work?', answer: 'CIDR uses a prefix length to split an IP address into network and host bits. From that prefix you can calculate the subnet mask, usable range, broadcast address, and route scope.' },
    { id: 'q24', category: 'Networking & Web', question: 'What information does a User-Agent string contain?', answer: 'A User-Agent string usually exposes the browser family, version, rendering engine, operating system, and sometimes device hints. It is useful for debugging, but it can be incomplete or intentionally misleading.' },
    { id: 'q25', category: 'Networking & Web', question: 'How do I use cURL to debug APIs?', answer: 'Start with the method, URL, headers, and body, then add verbose output to inspect the request and response. cURL is ideal for isolating network behavior from application code.' },
    { id: 'q26', category: 'Networking & Web', question: 'What is SAML and how does SSO work?', answer: 'SAML is an XML-based protocol used heavily in enterprise SSO. An identity provider authenticates the user and sends a signed assertion to the service provider so the user can access the app without a separate password.' },
    { id: 'q27', category: 'Networking & Web', question: 'What are SPF, DKIM, and DMARC in email security?', answer: 'SPF authorizes sending servers, DKIM signs the message, and DMARC tells receivers how to enforce failures. Together they reduce spoofing and improve trust in incoming mail.' },
    { id: 'q28', category: 'Developer Productivity', question: 'How do I estimate API token costs for LLMs?', answer: 'Estimate the prompt tokens, output tokens, and the pricing model for your provider, then calculate cost per request and at expected volume. The most important variables are model choice, context length, and response size.' },
    { id: 'q29', category: 'Developer Productivity', question: 'What is a cron expression and how do I write one?', answer: 'A cron expression is a compact schedule definition for recurring jobs. Build it field by field, verify the timezone, and preview the next run times before putting it into production.' },
    { id: 'q30', category: 'Developer Productivity', question: 'How do I create effective prompt templates for AI?', answer: 'Use a stable structure with clear instructions, placeholders for dynamic data, and explicit output requirements. Good prompt templates are reusable, testable, and narrow enough to reduce ambiguity.' }
  ],
  ko: [
    { id: 'q1', category: '일반', question: 'SimpleTool은 무엇이고 누가 사용하면 좋나요?', answer: 'SimpleTool은 개발자, 운영자, 파워 유저를 위한 프라이버시 우선 브라우저 도구 모음입니다. JSON 포맷팅, 토큰 검사, 자격 증명 생성 같은 작업을 서버가 아니라 브라우저 안에서 처리하도록 설계되었습니다.' },
    { id: 'q2', category: '일반', question: 'SimpleTool은 정말 무료인가요?', answer: '네. 공개 사이트의 핵심 도구는 무료로 사용할 수 있으며, 운영과 유지보수 비용의 일부를 광고로 충당합니다.' },
    { id: 'q3', category: '일반', question: '계정을 만들어야 하나요?', answer: '아니요. 회원가입이나 로그인 없이 바로 도구를 열어 사용할 수 있습니다.' },
    { id: 'q4', category: '일반', question: '내 데이터는 안전한가요? 클라이언트 사이드 처리는 어떻게 동작하나요?', answer: '대부분의 도구는 JavaScript와 브라우저 API로 로컬 처리됩니다. 즉, 사용자가 직접 복사하거나 저장하지 않는 한 입력 데이터는 보통 기기 밖으로 나가지 않습니다.' },
    { id: 'q5', category: '일반', question: '어떤 브라우저를 지원하나요?', answer: '최신 Chrome, Edge, Firefox, Safari와 최신 모바일 브라우저를 지원합니다. ES 모듈이나 Web Crypto를 지원하지 않는 오래된 브라우저는 정상 동작하지 않을 수 있습니다.' },
    { id: 'q6', category: '일반', question: '오프라인으로도 사용할 수 있나요?', answer: '많은 도구는 페이지가 로드된 뒤 인터넷이 끊겨도 계속 동작합니다. 다만 안정적인 오프라인 운영이 필요하다면 자체 호스팅이 가장 확실합니다.' },
    { id: 'q7', category: '보안 및 암호화', question: '정말 안전한 비밀번호의 조건은 무엇인가요?', answer: '안전한 비밀번호는 길고, 무작위이며, 서비스마다 고유해야 합니다. 기억하기 쉬운 규칙보다 길이와 예측 불가능성이 더 중요합니다.' },
    { id: 'q8', category: '보안 및 암호화', question: 'MD5, SHA-256, SHA-512의 차이는 무엇인가요?', answer: 'MD5는 보안용으로 더 이상 적합하지 않습니다. SHA-256과 SHA-512는 현대적인 SHA-2 계열이며, SHA-512는 출력이 더 길고 SHA-256은 무결성 검증과 서명 워크플로에서 널리 쓰입니다.' },
    { id: 'q9', category: '보안 및 암호화', question: '왜 MD5는 깨진 알고리즘으로 취급되나요?', answer: '서로 다른 입력이 같은 해시를 만들도록 충돌을 실용적으로 생성할 수 있기 때문입니다. 그래서 신뢰 검증, 서명, 비밀번호 저장에는 사용하면 안 됩니다.' },
    { id: 'q10', category: '보안 및 암호화', question: 'HMAC은 무엇이고 언제 써야 하나요?', answer: 'HMAC은 해시 함수와 공유 비밀키를 결합한 방식입니다. 서명된 API 요청이나 웹훅 검증처럼 무결성과 송신자 인증이 둘 다 필요할 때 사용합니다.' },
    { id: 'q11', category: '보안 및 암호화', question: '비밀번호 해싱에서 bcrypt와 Argon2는 어떻게 다른가요?', answer: '둘 다 비밀번호 저장용으로 설계됐지만, Argon2는 메모리 비용을 크게 활용해 GPU 공격에 더 강한 현대적 선택지입니다. bcrypt는 호환성 때문에 여전히 많이 사용됩니다.' },
    { id: 'q12', category: '보안 및 암호화', question: 'JWT는 무엇이며 언제 사용하나요?', answer: 'JWT는 시스템 간 클레임을 전달하는 간결한 토큰 형식입니다. 무상태 인증이나 서비스 간 신원 전달에 유용하지만, 서명 검증과 만료 처리, 저장 방식이 제대로 설계되어야 합니다.' },
    { id: 'q13', category: '보안 및 암호화', question: '해시 체크섬으로 파일 무결성을 어떻게 검증하나요?', answer: '다운로드한 파일의 해시를 로컬에서 계산한 뒤 배포자가 제공한 공식 값과 정확히 비교하면 됩니다. 값이 같다면 파일이 바뀌지 않았을 가능성이 매우 높습니다.' },
    { id: 'q14', category: '보안 및 암호화', question: 'CSP(Content Security Policy)는 무엇이고 왜 중요한가요?', answer: 'CSP는 스크립트, 스타일, 이미지 같은 리소스의 허용 출처를 제한하는 브라우저 보안 정책입니다. XSS와 악성 스크립트 주입을 막는 데 매우 강력한 방어선입니다.' },
    { id: 'q15', category: '데이터 포맷', question: 'JSON과 YAML의 차이는 무엇인가요?', answer: 'JSON은 더 엄격하고 예측 가능해서 API와 시스템 간 교환에 적합합니다. YAML은 사람이 읽기 편하지만 들여쓰기와 확장 문법 때문에 숨은 오류가 생기기 쉽습니다.' },
    { id: 'q16', category: '데이터 포맷', question: 'JSON은 어떻게 검증하나요?', answer: '먼저 문법이 올바른지 확인하고, 계약이 필요한 데이터라면 스키마로 구조와 타입까지 검증해야 합니다. 문법 검사는 필드 존재나 타입 적합성까지 보장하지 않습니다.' },
    { id: 'q17', category: '데이터 포맷', question: 'Base64 인코딩은 무엇이고 언제 쓰나요?', answer: 'Base64는 바이너리 데이터를 텍스트 안전 형태로 바꾸는 인코딩입니다. 토큰, 이메일 본문, 데이터 URL, 텍스트 기반 전송 형식에서 자주 쓰입니다.' },
    { id: 'q18', category: '데이터 포맷', question: '정규식은 무엇이고 왜 유용한가요?', answer: '정규식은 텍스트를 찾고 바꾸기 위한 패턴 언어입니다. 검증, 추출, 치환, 로그 분석에 매우 유용하지만, 지나치게 복잡한 패턴은 성능 문제를 일으킬 수 있습니다.' },
    { id: 'q19', category: '데이터 포맷', question: '여러 타임스탬프 형식은 어떻게 변환하나요?', answer: '먼저 Unix 초, Unix 밀리초, ISO 8601 같은 기준 형식으로 정규화한 뒤 목표 형식과 타임존으로 다시 렌더링하면 됩니다. 대부분의 버그는 단위와 타임존 혼동에서 생깁니다.' },
    { id: 'q20', category: '데이터 포맷', question: 'UUID는 무엇이고 언제 사용하나요?', answer: 'UUID는 중앙 서버 없이도 생성할 수 있는 전역 고유 식별자입니다. 분산 시스템, 테스트 데이터, 예측하기 어려운 식별자가 필요한 경우에 적합합니다.' },
    { id: 'q21', category: '데이터 포맷', question: 'JSON Schema는 무엇이고 왜 써야 하나요?', answer: 'JSON Schema는 JSON 문서의 구조, 타입, 제약 조건을 정의합니다. API, 이벤트, 설정 파일을 일관되고 검증 가능하게 유지하는 데 도움이 됩니다.' },
    { id: 'q22', category: '데이터 포맷', question: '두 텍스트 파일의 차이는 어떻게 비교하나요?', answer: '추가, 삭제, 수정된 부분을 나란히 보여주는 diff 도구를 쓰는 것이 가장 좋습니다. 큰 파일을 눈으로 직접 비교하는 것보다 훨씬 빠르고 안전합니다.' },
    { id: 'q23', category: '네트워크 및 웹', question: 'CIDR 서브넷과 IP 범위는 어떻게 동작하나요?', answer: 'CIDR은 프리픽스 길이로 네트워크 비트와 호스트 비트를 나누는 방식입니다. 이 값으로 서브넷 마스크, 사용 가능한 IP 범위, 브로드캐스트 주소를 계산할 수 있습니다.' },
    { id: 'q24', category: '네트워크 및 웹', question: 'User-Agent 문자열에는 어떤 정보가 들어 있나요?', answer: '보통 브라우저 계열, 버전, 렌더링 엔진, 운영체제, 기기 힌트가 들어 있습니다. 다만 호환성 때문에 과장되거나 왜곡된 값이 섞여 있을 수 있습니다.' },
    { id: 'q25', category: '네트워크 및 웹', question: 'API 디버깅에 cURL은 어떻게 사용하나요?', answer: '메서드, URL, 헤더, 바디를 먼저 명시하고 verbose 출력을 켜서 요청과 응답을 확인하면 됩니다. 애플리케이션 코드 문제와 네트워크 문제를 분리하는 데 특히 유용합니다.' },
    { id: 'q26', category: '네트워크 및 웹', question: 'SAML은 무엇이며 SSO는 어떻게 동작하나요?', answer: 'SAML은 엔터프라이즈 SSO에서 많이 쓰이는 XML 기반 프로토콜입니다. IdP가 사용자를 인증하고 서명된 assertion을 서비스에 전달해 별도 비밀번호 없이 로그인하게 합니다.' },
    { id: 'q27', category: '네트워크 및 웹', question: '이메일 보안에서 SPF, DKIM, DMARC는 무엇인가요?', answer: 'SPF는 발신 서버를 허용하고, DKIM은 메시지에 서명하며, DMARC는 실패 시 수신 서버가 어떻게 처리할지 규정합니다. 세 가지를 함께 써야 스푸핑 방어 효과가 큽니다.' },
    { id: 'q28', category: '개발 생산성', question: 'LLM API 토큰 비용은 어떻게 추정하나요?', answer: '프롬프트 토큰, 출력 토큰, 공급자의 과금 단가를 기준으로 요청당 비용과 예상 트래픽 비용을 계산하면 됩니다. 모델 종류와 응답 길이가 가장 큰 변수입니다.' },
    { id: 'q29', category: '개발 생산성', question: '크론 표현식은 무엇이고 어떻게 작성하나요?', answer: '크론 표현식은 반복 작업 일정을 정의하는 압축 문법입니다. 각 필드를 순서대로 작성하고, 실제 적용 전에는 타임존과 다음 실행 시점을 꼭 확인해야 합니다.' },
    { id: 'q30', category: '개발 생산성', question: 'AI용 프롬프트 템플릿은 어떻게 잘 만드나요?', answer: '고정된 지시문, 변수 자리표시자, 원하는 출력 형식을 분리해서 설계하세요. 좋은 템플릿은 재사용 가능하고 테스트 가능하며, 불필요한 모호성을 줄입니다.' }
  ],
  ja: [
    { id: 'q1', category: '一般', question: 'SimpleTool とは何で、誰向けですか？', answer: 'SimpleTool は、開発者、運用担当者、パワーユーザー向けのプライバシー重視ブラウザツール集です。JSON 整形やトークン確認、資格情報生成などをサーバーではなくブラウザ内で処理する設計です。' },
    { id: 'q2', category: '一般', question: 'SimpleTool は本当に無料ですか？', answer: 'はい。公開サイトの主要ツールは無料で利用でき、運営費や保守費の一部を広告でまかなっています。' },
    { id: 'q3', category: '一般', question: 'アカウント作成は必要ですか？', answer: '不要です。登録やログインなしで、そのままツールを開いて使えます。' },
    { id: 'q4', category: '一般', question: 'データは安全ですか？ クライアントサイド処理はどう動きますか？', answer: '多くのツールは JavaScript とブラウザ API を使って端末内で処理されます。利用者が自分でコピーや保存をしない限り、入力データは通常端末の外に出ません。' },
    { id: 'q5', category: '一般', question: 'どのブラウザをサポートしていますか？', answer: '最新の Chrome、Edge、Firefox、Safari と最新モバイルブラウザを想定しています。ES モジュールや Web Crypto を持たない古いブラウザでは正常に動かないことがあります。' },
    { id: 'q6', category: '一般', question: 'オフラインでも使えますか？', answer: '多くのツールは初回ロード後なら回線が切れても動き続けます。安定したオフライン運用が必要なら、自前でホスティングする方法が最も確実です。' },
    { id: 'q7', category: 'セキュリティと暗号', question: '本当に安全なパスワードの条件は何ですか？', answer: '安全なパスワードは、長く、ランダムで、サービスごとに固有であることです。覚えやすい規則よりも、長さと予測しにくさが重要です。' },
    { id: 'q8', category: 'セキュリティと暗号', question: 'MD5、SHA-256、SHA-512 の違いは何ですか？', answer: 'MD5 は安全用途には不適切です。SHA-256 と SHA-512 は現代的な SHA-2 系で、SHA-512 は出力が長く、SHA-256 は整合性確認や署名用途で広く使われます。' },
    { id: 'q9', category: 'セキュリティと暗号', question: 'なぜ MD5 は壊れていると見なされるのですか？', answer: '異なる入力で同じハッシュを作る衝突が実用的に作れてしまうためです。そのため、信頼確認、署名、パスワード保存には使うべきではありません。' },
    { id: 'q10', category: 'セキュリティと暗号', question: 'HMAC とは何で、いつ使うべきですか？', answer: 'HMAC はハッシュ関数に共有秘密鍵を組み合わせた仕組みです。署名付き API リクエストや Webhook 検証のように、完全性と送信者確認の両方が必要な場面で使います。' },
    { id: 'q11', category: 'セキュリティと暗号', question: 'パスワードハッシュでは bcrypt と Argon2 はどう違いますか？', answer: 'どちらもパスワード保存向けですが、Argon2 はメモリコストを活用できるため GPU 攻撃に強い現代的な選択肢です。bcrypt は互換性のため今も広く使われています。' },
    { id: 'q12', category: 'セキュリティと暗号', question: 'JWT とは何で、いつ使いますか？', answer: 'JWT はシステム間でクレームを運ぶためのコンパクトなトークン形式です。ステートレス認証やサービス間の ID 伝播に向いていますが、署名検証と有効期限管理を正しく実装する必要があります。' },
    { id: 'q13', category: 'セキュリティと暗号', question: 'ハッシュチェックサムでファイル整合性を確認するには？', answer: 'ダウンロードしたファイルのハッシュをローカルで計算し、配布元が公開している公式値と完全一致するか比較します。一致すれば、改変されていない可能性が高いです。' },
    { id: 'q14', category: 'セキュリティと暗号', question: 'CSP（Content Security Policy）とは何で、なぜ重要ですか？', answer: 'CSP は、スクリプトやスタイルなどの読み込み元を制限するブラウザセキュリティポリシーです。XSS や悪意あるコンテンツ注入を防ぐ非常に強力な対策です。' },
    { id: 'q15', category: 'データ形式', question: 'JSON と YAML の違いは何ですか？', answer: 'JSON は厳格で予測しやすく、API や機械間通信に向いています。YAML は人が読みやすい反面、インデントや拡張構文によるミスが起きやすいです。' },
    { id: 'q16', category: 'データ形式', question: 'JSON はどう検証すればよいですか？', answer: 'まず構文が正しいか確認し、契約が必要なデータであればスキーマで構造や型まで検証します。構文だけでは必要なフィールドや型までは保証できません。' },
    { id: 'q17', category: 'データ形式', question: 'Base64 エンコードとは何で、いつ使われますか？', answer: 'Base64 はバイナリをテキスト安全な形に変えるエンコードです。トークン、メール本文、データ URL、テキスト前提の転送形式でよく使われます。' },
    { id: 'q18', category: 'データ形式', question: '正規表現とは何で、なぜ便利なのですか？', answer: '正規表現は文字列を検索・抽出・置換するためのパターン言語です。検証やログ解析に便利ですが、複雑にしすぎると性能問題を招きます。' },
    { id: 'q19', category: 'データ形式', question: '異なるタイムスタンプ形式はどう変換しますか？', answer: 'Unix 秒、Unix ミリ秒、ISO 8601 などの基準形式に正規化してから、目的の形式とタイムゾーンで再表示します。多くの不具合は単位やタイムゾーンの取り違えから生まれます。' },
    { id: 'q20', category: 'データ形式', question: 'UUID とは何で、いつ使うべきですか？', answer: 'UUID は中央サーバーなしで生成できるグローバル一意識別子です。分散システム、テストデータ、推測されにくい ID が必要な場面に向いています。' },
    { id: 'q21', category: 'データ形式', question: 'JSON Schema とは何で、なぜ使うべきですか？', answer: 'JSON Schema は JSON 文書の構造、型、制約を定義します。API、イベント、設定ファイルを一貫して検証可能な状態に保つのに役立ちます。' },
    { id: 'q22', category: 'データ形式', question: '2 つのテキストファイルの違いはどう比較しますか？', answer: '追加、削除、変更を並べて見せる diff ツールを使うのが最適です。大きなファイルを目視で比べるより、ずっと速くて安全です。' },
    { id: 'q23', category: 'ネットワークと Web', question: 'CIDR サブネットと IP 範囲はどう動きますか？', answer: 'CIDR はプレフィックス長でネットワーク部とホスト部を分ける考え方です。その値からサブネットマスク、利用可能範囲、ブロードキャストアドレスを計算できます。' },
    { id: 'q24', category: 'ネットワークと Web', question: 'User-Agent 文字列にはどんな情報が入っていますか？', answer: '通常はブラウザ系統、バージョン、レンダリングエンジン、OS、端末ヒントなどが入ります。ただし互換性のために誇張や偽装が混ざることもあります。' },
    { id: 'q25', category: 'ネットワークと Web', question: 'API デバッグに cURL をどう使いますか？', answer: 'メソッド、URL、ヘッダー、本文を明示し、verbose 出力で送受信内容を確認します。アプリのコード由来の問題とネットワーク由来の問題を切り分けるのに最適です。' },
    { id: 'q26', category: 'ネットワークと Web', question: 'SAML とは何で、SSO はどう動きますか？', answer: 'SAML は企業向け SSO で広く使われる XML ベースのプロトコルです。IdP がユーザーを認証し、署名付きアサーションをサービスへ渡すことで再ログインなしにアクセスできます。' },
    { id: 'q27', category: 'ネットワークと Web', question: 'メールセキュリティの SPF、DKIM、DMARC とは何ですか？', answer: 'SPF は送信元サーバーを許可し、DKIM はメッセージへ署名し、DMARC は失敗時の扱いを定義します。3 つを組み合わせることでなりすまし対策が強くなります。' },
    { id: 'q28', category: '開発生産性', question: 'LLM API のトークンコストはどう見積もりますか？', answer: '入力トークン、出力トークン、プロバイダの単価から 1 リクエストあたりと想定トラフィック全体のコストを計算します。モデル種類と出力量が最も大きな要素です。' },
    { id: 'q29', category: '開発生産性', question: 'cron 式とは何で、どう書けばよいですか？', answer: 'cron 式は定期ジョブのスケジュールを表す短い記法です。各フィールドを順に組み立て、投入前にタイムゾーンと次回実行時刻を必ず確認してください。' },
    { id: 'q30', category: '開発生産性', question: 'AI 向けの良いプロンプトテンプレートはどう作りますか？', answer: '固定の指示、差し替え変数、期待する出力形式を分離して設計します。良いテンプレートは再利用でき、テストでき、曖昧さを減らせるものです。' }
  ],
  es: [
    { id: 'q1', category: 'General', question: '¿Qué es SimpleTool y para quién está pensado?', answer: 'SimpleTool es una colección de utilidades para navegador enfocada en privacidad, pensada para desarrolladores, operadores y usuarios avanzados. Tareas como formatear JSON, inspeccionar tokens o generar credenciales se ejecutan en el navegador, no en nuestros servidores.' },
    { id: 'q2', category: 'General', question: '¿SimpleTool es realmente gratis?', answer: 'Sí. Las herramientas principales del sitio público son gratuitas y parte de los costes de operación y mantenimiento se cubren con publicidad.' },
    { id: 'q3', category: 'General', question: '¿Necesito crear una cuenta?', answer: 'No. Puedes abrir cualquier herramienta y usarla al instante sin registrarte ni iniciar sesión.' },
    { id: 'q4', category: 'General', question: '¿Mis datos están seguros? ¿Cómo funciona el procesamiento del lado del cliente?', answer: 'La mayoría de las herramientas procesan los datos localmente con JavaScript y APIs del navegador. Eso significa que la información suele quedarse en tu dispositivo salvo que tú decidas copiarla, exportarla o enviarla a otro lugar.' },
    { id: 'q5', category: 'General', question: '¿Qué navegadores son compatibles?', answer: 'SimpleTool está pensado para versiones modernas de Chrome, Edge, Firefox y Safari, además de navegadores móviles actuales. Navegadores antiguos sin ES modules o Web Crypto pueden fallar.' },
    { id: 'q6', category: 'General', question: '¿Puedo usar SimpleTool sin conexión?', answer: 'Muchas herramientas siguen funcionando después de cargar la página porque la lógica es local. Si necesitas un flujo offline fiable, lo más seguro es autoalojar el proyecto.' },
    { id: 'q7', category: 'Seguridad y criptografía', question: '¿Qué hace que una contraseña sea realmente segura?', answer: 'Una contraseña segura es larga, aleatoria y única para cada servicio. La longitud y la imprevisibilidad importan más que los trucos fáciles de recordar.' },
    { id: 'q8', category: 'Seguridad y criptografía', question: '¿Cuál es la diferencia entre MD5, SHA-256 y SHA-512?', answer: 'MD5 ya no es adecuado para seguridad. SHA-256 y SHA-512 pertenecen a la familia SHA-2; SHA-512 produce una salida más larga y SHA-256 es el valor por defecto más común para integridad y firmas.' },
    { id: 'q9', category: 'Seguridad y criptografía', question: '¿Por qué se considera roto MD5?', answer: 'Porque existen ataques de colisión prácticos que permiten generar entradas distintas con el mismo hash. Por eso no debe usarse para confianza, firmas ni almacenamiento de contraseñas.' },
    { id: 'q10', category: 'Seguridad y criptografía', question: '¿Qué es HMAC y cuándo debería usarlo?', answer: 'HMAC combina una función hash con una clave secreta compartida. Úsalo cuando necesites integridad y autenticidad al mismo tiempo, por ejemplo en firmas de API o validación de webhooks.' },
    { id: 'q11', category: 'Seguridad y criptografía', question: '¿Cómo se compara bcrypt con Argon2 para el hash de contraseñas?', answer: 'Ambos están diseñados para contraseñas, pero Argon2 es la opción moderna porque permite endurecer el coste de memoria frente a ataques con GPU. bcrypt sigue siendo común por compatibilidad.' },
    { id: 'q12', category: 'Seguridad y criptografía', question: '¿Qué es un JWT y cuándo debería usarlo?', answer: 'Un JWT es un formato compacto de token para transportar claims entre sistemas. Es útil para autenticación sin estado y para identidad entre servicios, siempre que la firma, la expiración y la validación estén bien resueltas.' },
    { id: 'q13', category: 'Seguridad y criptografía', question: '¿Cómo verifico la integridad de un archivo con checksums hash?', answer: 'Calcula el hash del archivo localmente y compáralo con el valor oficial publicado por quien lo distribuye. Si coinciden exactamente, es muy probable que el archivo no haya sido alterado.' },
    { id: 'q14', category: 'Seguridad y criptografía', question: '¿Qué es Content Security Policy (CSP) y por qué importa?', answer: 'CSP es una política de seguridad del navegador que restringe de dónde pueden cargarse scripts, estilos, imágenes y otros recursos. Es una defensa muy fuerte contra XSS y contenido inyectado.' },
    { id: 'q15', category: 'Formatos de datos', question: '¿Cuál es la diferencia entre JSON y YAML?', answer: 'JSON es más estricto y predecible, por lo que suele ser mejor para APIs e intercambio entre sistemas. YAML es más cómodo para humanos, pero su sintaxis e indentación pueden causar errores sutiles.' },
    { id: 'q16', category: 'Formatos de datos', question: '¿Cómo valido JSON?', answer: 'Primero valida la sintaxis y, si el dato debe seguir un contrato, valida también la estructura con un schema. Tener JSON válido no garantiza campos ni tipos correctos.' },
    { id: 'q17', category: 'Formatos de datos', question: '¿Qué es la codificación Base64 y cuándo se usa?', answer: 'Base64 convierte datos binarios en un formato seguro para texto. Se usa mucho en tokens, emails, data URLs y transportes que solo aceptan texto.' },
    { id: 'q18', category: 'Formatos de datos', question: '¿Qué son las expresiones regulares y por qué son útiles?', answer: 'Las expresiones regulares son patrones compactos para buscar y transformar texto. Son muy útiles para validación, extracción y limpieza, aunque conviene escribirlas con cuidado para evitar complejidad y problemas de rendimiento.' },
    { id: 'q19', category: 'Formatos de datos', question: '¿Cómo convierto entre distintos formatos de timestamp?', answer: 'Normaliza primero a una referencia clara como Unix en segundos, Unix en milisegundos o ISO 8601, y luego renderiza al formato y zona horaria de destino. Muchos errores vienen de confundir unidades u horarios.' },
    { id: 'q20', category: 'Formatos de datos', question: '¿Qué es un UUID y cuándo debería usarlo?', answer: 'Un UUID es un identificador global único que puede generarse sin una base de datos central. Es útil en sistemas distribuidos, datos de prueba e identificadores que no conviene enumerar fácilmente.' },
    { id: 'q21', category: 'Formatos de datos', question: '¿Qué es JSON Schema y por qué debería usarlo?', answer: 'JSON Schema define la estructura, los tipos y las reglas permitidas para documentos JSON. Ayuda a mantener APIs, eventos y archivos de configuración de forma coherente y verificable.' },
    { id: 'q22', category: 'Formatos de datos', question: '¿Cómo comparo dos archivos de texto para ver diferencias?', answer: 'Lo mejor es usar una herramienta de diff que resalte lo añadido, eliminado y modificado lado a lado. Es mucho más rápido y seguro que revisar archivos grandes manualmente.' },
    { id: 'q23', category: 'Red y web', question: '¿Cómo funcionan las subredes CIDR y los rangos IP?', answer: 'CIDR usa una longitud de prefijo para dividir una IP en bits de red y de host. A partir de ese prefijo puedes calcular máscara, rango utilizable, broadcast y alcance de la ruta.' },
    { id: 'q24', category: 'Red y web', question: '¿Qué información contiene una cadena User-Agent?', answer: 'Normalmente incluye la familia del navegador, la versión, el motor de renderizado, el sistema operativo y algunas pistas del dispositivo. Aun así, puede contener información engañosa por compatibilidad.' },
    { id: 'q25', category: 'Red y web', question: '¿Cómo uso cURL para depurar APIs?', answer: 'Empieza con método, URL, cabeceras y cuerpo, y luego activa la salida verbose para inspeccionar petición y respuesta. cURL es ideal para aislar el comportamiento de red del código de la aplicación.' },
    { id: 'q26', category: 'Red y web', question: '¿Qué es SAML y cómo funciona el SSO?', answer: 'SAML es un protocolo basado en XML muy usado en SSO empresarial. Un proveedor de identidad autentica al usuario y envía una assertion firmada al servicio para permitir acceso sin otra contraseña.' },
    { id: 'q27', category: 'Red y web', question: '¿Qué son SPF, DKIM y DMARC en la seguridad del correo?', answer: 'SPF autoriza servidores remitentes, DKIM firma el mensaje y DMARC define cómo actuar si algo falla. Juntos reducen el spoofing y mejoran la confianza del correo entrante.' },
    { id: 'q28', category: 'Productividad para desarrolladores', question: '¿Cómo estimo el coste de tokens de una API para LLMs?', answer: 'Calcula los tokens de entrada, los de salida y la tarifa del proveedor para obtener el coste por solicitud y a volumen esperado. Las variables clave son el modelo, el contexto y el tamaño de la respuesta.' },
    { id: 'q29', category: 'Productividad para desarrolladores', question: '¿Qué es una expresión cron y cómo se escribe?', answer: 'Una expresión cron es una forma compacta de definir tareas recurrentes. Construye cada campo paso a paso y verifica la zona horaria y las próximas ejecuciones antes de usarla en producción.' },
    { id: 'q30', category: 'Productividad para desarrolladores', question: '¿Cómo creo buenas plantillas de prompts para IA?', answer: 'Usa una estructura estable con instrucciones claras, variables bien delimitadas y un formato de salida explícito. Una buena plantilla es reutilizable, comprobable y reduce la ambigüedad.' }
  ],
  'zh-CN': [
    { id: 'q1', category: '常规', question: 'SimpleTool 是什么，适合哪些用户？', answer: 'SimpleTool 是一套以隐私为优先的浏览器工具集，面向开发者、运维人员和高级用户。JSON 格式化、令牌解析、凭据生成等操作都在浏览器本地完成，不经过服务器。' },
    { id: 'q2', category: '常规', question: 'SimpleTool 真的免费吗？', answer: '是的。公共站点的核心工具完全免费，部分运营和维护费用通过广告覆盖，无需付费订阅。' },
    { id: 'q3', category: '常规', question: '需要注册账号吗？', answer: '不需要。无需注册或登录，打开工具即可直接使用。' },
    { id: 'q4', category: '常规', question: '我的数据安全吗？客户端处理是怎么工作的？', answer: '大多数工具使用 JavaScript 和浏览器 API 在本地处理数据，输入内容通常不会离开您的设备，除非您主动复制、导出或发送到其他地方。' },
    { id: 'q5', category: '常规', question: '支持哪些浏览器？', answer: 'SimpleTool 支持最新版本的 Chrome、Edge、Firefox 和 Safari，以及最新移动浏览器。不支持 ES 模块或 Web Crypto 的旧版浏览器可能无法正常运行。' },
    { id: 'q6', category: '常规', question: '可以离线使用 SimpleTool 吗？', answer: '页面加载后，许多工具在断网状态下仍可继续运行，因为逻辑在客户端执行。如需可靠的离线工作流，建议自行托管项目。' },
    { id: 'q7', category: '安全与密码学', question: '真正安全的密码需要具备哪些条件？', answer: '安全的密码应足够长、随机，且每个服务使用唯一密码。长度和不可预测性比任何容易记忆的规律都更重要。' },
    { id: 'q8', category: '安全与密码学', question: 'MD5、SHA-256 和 SHA-512 有什么区别？', answer: 'MD5 已不适合用于安全场景。SHA-256 和 SHA-512 同属现代 SHA-2 系列：SHA-512 输出更长，SHA-256 是完整性校验和签名工作流中最常用的默认选择。' },
    { id: 'q9', category: '安全与密码学', question: '为什么 MD5 被认为已经破损？', answer: '攻击者可以构造两个不同的输入产生相同的哈希值，即碰撞攻击已可实际利用。因此 MD5 不适用于信任验证、数字签名或密码存储。' },
    { id: 'q10', category: '安全与密码学', question: 'HMAC 是什么，什么时候应该使用它？', answer: 'HMAC 将哈希函数与共享密钥结合使用。当您同时需要完整性和身份验证时，例如签名 API 请求或 Webhook 验证，应使用 HMAC。' },
    { id: 'q11', category: '安全与密码学', question: '密码哈希中 bcrypt 和 Argon2 有何区别？', answer: '两者都是专为密码哈希设计的算法，但 Argon2 是更现代的选择，因为它具有内存硬度特性，更难被 GPU 攻击。bcrypt 因兼容性仍被广泛使用。' },
    { id: 'q12', category: '安全与密码学', question: 'JWT 是什么，什么时候应该使用它？', answer: 'JWT 是一种用于在系统间传递声明的紧凑令牌格式，适用于无状态认证和服务间身份传递，但前提是签名、过期时间和验证逻辑都需正确实现。' },
    { id: 'q13', category: '安全与密码学', question: '如何使用哈希校验和验证文件完整性？', answer: '在本地计算文件的哈希值，然后与发布方提供的官方值进行精确比对。若完全一致，则文件极可能未被篡改。' },
    { id: 'q14', category: '安全与密码学', question: '内容安全策略（CSP）是什么，为什么重要？', answer: 'CSP 是浏览器强制执行的安全策略，限制脚本、样式、图片等资源的加载来源。它是抵御 XSS 和恶意内容注入最有效的防线之一。' },
    { id: 'q15', category: '数据格式', question: 'JSON 和 YAML 有什么区别？', answer: 'JSON 更严格、更可预测，通常更适合 API 和机器间交换。YAML 对人类更友好，但缩进和高级语法容易引入隐藏错误。' },
    { id: 'q16', category: '数据格式', question: '如何验证 JSON？', answer: '首先检查语法是否正确，若数据需要遵循某种契约，还应使用 Schema 验证结构和类型。仅通过语法验证无法保证字段和类型的正确性。' },
    { id: 'q17', category: '数据格式', question: 'Base64 编码是什么，什么时候使用？', answer: 'Base64 是将二进制数据转换为纯文本安全格式的编码方式。常用于令牌、邮件负载、Data URL 以及只支持纯文本的传输格式。' },
    { id: 'q18', category: '数据格式', question: '正则表达式是什么，为什么有用？', answer: '正则表达式是用于匹配和转换文本的紧凑模式语言。在验证、提取、搜索和数据清理方面非常有用，但需谨慎编写以避免复杂性和性能问题。' },
    { id: 'q19', category: '数据格式', question: '如何在不同时间戳格式之间转换？', answer: '先将源时间戳规范化为明确的参考格式（如 Unix 秒、Unix 毫秒或 ISO 8601），再渲染为目标格式和时区。大多数时间戳问题源于时区和单位混淆。' },
    { id: 'q20', category: '数据格式', question: 'UUID 是什么，什么时候应该使用它？', answer: 'UUID 是可以在无需中央数据库的情况下生成的全局唯一标识符，适用于分布式系统、测试数据以及不应轻易被枚举的标识符场景。' },
    { id: 'q21', category: '数据格式', question: 'JSON Schema 是什么，为什么要使用它？', answer: 'JSON Schema 定义了 JSON 文档允许的结构、类型和规则，有助于保持 API、事件和配置文件的一致性和可测试性。' },
    { id: 'q22', category: '数据格式', question: '如何比较两个文本文件的差异？', answer: '使用能并排显示新增、删除和修改内容的 diff 工具。这比手动扫描大文件更快、更安全。' },
    { id: 'q23', category: '网络与 Web', question: 'CIDR 子网和 IP 范围是如何工作的？', answer: 'CIDR 使用前缀长度将 IP 地址划分为网络位和主机位。根据前缀可以计算出子网掩码、可用地址范围、广播地址和路由范围。' },
    { id: 'q24', category: '网络与 Web', question: 'User-Agent 字符串包含哪些信息？', answer: 'User-Agent 字符串通常包含浏览器系列、版本、渲染引擎、操作系统及设备提示，但出于兼容性考虑，其中的信息可能不完整甚至被刻意伪造。' },
    { id: 'q25', category: '网络与 Web', question: '如何使用 cURL 调试 API？', answer: '从方法、URL、请求头和请求体开始，然后添加 verbose 输出以检查请求和响应。cURL 非常适合将网络行为从应用代码中隔离出来单独排查。' },
    { id: 'q26', category: '网络与 Web', question: 'SAML 是什么，SSO 是如何工作的？', answer: 'SAML 是企业 SSO 中广泛使用的基于 XML 的协议。身份提供商对用户进行身份验证，然后将已签名的断言发送给服务提供商，用户无需单独输入密码即可访问应用。' },
    { id: 'q27', category: '网络与 Web', question: '邮件安全中的 SPF、DKIM 和 DMARC 是什么？', answer: 'SPF 授权发送服务器，DKIM 对邮件进行签名，DMARC 告知接收方如何处理验证失败的邮件。三者配合使用可有效减少欺骗并提升邮件信任度。' },
    { id: 'q28', category: '开发者效率', question: '如何估算 LLM 的 API token 费用？', answer: '估算提示词 token 数、输出 token 数以及供应商的计费标准，然后计算每次请求的费用和预期流量下的总成本。最关键的变量是模型选择、上下文长度和响应大小。' },
    { id: 'q29', category: '开发者效率', question: 'cron 表达式是什么，如何编写？', answer: 'cron 表达式是定义定期任务计划的紧凑语法。逐字段构建，在投入生产前务必验证时区并预览下次执行时间。' },
    { id: 'q30', category: '开发者效率', question: '如何为 AI 创建有效的提示词模板？', answer: '使用包含清晰指令、动态数据占位符和明确输出要求的稳定结构。好的提示词模板应可复用、可测试，且足够具体以减少歧义。' }
  ],
  'zh-TW': [
    { id: 'q1', category: '一般', question: 'SimpleTool 是什麼，適合哪些使用者？', answer: 'SimpleTool 是一套以隱私為優先的瀏覽器工具集，專為開發者、維運人員和進階使用者設計。JSON 格式化、令牌解析、憑證產生等操作都在瀏覽器本機執行，不經過伺服器。' },
    { id: 'q2', category: '一般', question: 'SimpleTool 真的免費嗎？', answer: '是的。公開網站的核心工具完全免費，部分營運和維護費用透過廣告支應，無需付費訂閱。' },
    { id: 'q3', category: '一般', question: '需要建立帳號嗎？', answer: '不需要。無需註冊或登入，開啟工具即可直接使用。' },
    { id: 'q4', category: '一般', question: '我的資料安全嗎？用戶端處理是如何運作的？', answer: '大多數工具使用 JavaScript 和瀏覽器 API 在本機處理資料，輸入內容通常不會離開您的裝置，除非您主動複製、匯出或傳送到其他地方。' },
    { id: 'q5', category: '一般', question: '支援哪些瀏覽器？', answer: 'SimpleTool 支援最新版本的 Chrome、Edge、Firefox 和 Safari，以及最新行動瀏覽器。不支援 ES 模組或 Web Crypto 的舊版瀏覽器可能無法正常運作。' },
    { id: 'q6', category: '一般', question: '可以離線使用 SimpleTool 嗎？', answer: '頁面載入後，許多工具在斷線狀態下仍可繼續運作，因為邏輯在用戶端執行。若需要可靠的離線工作流程，建議自行託管專案。' },
    { id: 'q7', category: '安全性與密碼學', question: '真正安全的密碼需要具備哪些條件？', answer: '安全的密碼應足夠長、隨機，且每個服務使用唯一密碼。長度和不可預測性比任何容易記憶的規律都更重要。' },
    { id: 'q8', category: '安全性與密碼學', question: 'MD5、SHA-256 和 SHA-512 有什麼差異？', answer: 'MD5 已不適合用於安全場景。SHA-256 和 SHA-512 同屬現代 SHA-2 系列：SHA-512 輸出較長，SHA-256 是完整性驗證和簽名工作流程中最常用的預設選擇。' },
    { id: 'q9', category: '安全性與密碼學', question: '為什麼 MD5 被認為已經損毀？', answer: '攻擊者可以構造兩個不同的輸入產生相同的雜湊值，即碰撞攻擊已可實際利用。因此 MD5 不適用於信任驗證、數位簽章或密碼儲存。' },
    { id: 'q10', category: '安全性與密碼學', question: 'HMAC 是什麼，什麼時候應該使用它？', answer: 'HMAC 將雜湊函式與共享密鑰結合使用。當您同時需要完整性和身份驗證時，例如簽名 API 請求或 Webhook 驗證，應使用 HMAC。' },
    { id: 'q11', category: '安全性與密碼學', question: '密碼雜湊中 bcrypt 和 Argon2 有何差異？', answer: '兩者都是專為密碼雜湊設計的演算法，但 Argon2 是更現代的選擇，因為它具有記憶體硬度特性，更難被 GPU 攻擊。bcrypt 因相容性仍被廣泛使用。' },
    { id: 'q12', category: '安全性與密碼學', question: 'JWT 是什麼，什麼時候應該使用它？', answer: 'JWT 是一種用於在系統間傳遞聲明的緊湊令牌格式，適用於無狀態認證和服務間身份傳遞，但前提是簽名、過期時間和驗證邏輯都需正確實作。' },
    { id: 'q13', category: '安全性與密碼學', question: '如何使用雜湊校驗和驗證檔案完整性？', answer: '在本機計算檔案的雜湊值，然後與發布方提供的官方值進行精確比對。若完全一致，則檔案極可能未被竄改。' },
    { id: 'q14', category: '安全性與密碼學', question: '內容安全政策（CSP）是什麼，為什麼重要？', answer: 'CSP 是瀏覽器強制執行的安全政策，限制腳本、樣式、圖片等資源的載入來源。它是抵禦 XSS 和惡意內容注入最有效的防線之一。' },
    { id: 'q15', category: '資料格式', question: 'JSON 和 YAML 有什麼差異？', answer: 'JSON 更嚴格、更可預測，通常更適合 API 和機器間交換。YAML 對人類更友善，但縮排和進階語法容易引入隱藏錯誤。' },
    { id: 'q16', category: '資料格式', question: '如何驗證 JSON？', answer: '首先檢查語法是否正確，若資料需要遵循某種契約，還應使用 Schema 驗證結構和型別。僅通過語法驗證無法保證欄位和型別的正確性。' },
    { id: 'q17', category: '資料格式', question: 'Base64 編碼是什麼，什麼時候使用？', answer: 'Base64 是將二進位資料轉換為純文字安全格式的編碼方式，常用於令牌、電子郵件負載、Data URL 以及只支援純文字的傳輸格式。' },
    { id: 'q18', category: '資料格式', question: '正規表示式是什麼，為什麼有用？', answer: '正規表示式是用於比對和轉換文字的緊湊模式語言，在驗證、擷取、搜尋和資料清理方面非常有用，但需謹慎編寫以避免複雜性和效能問題。' },
    { id: 'q19', category: '資料格式', question: '如何在不同時間戳記格式之間轉換？', answer: '先將來源時間戳記規範化為明確的參考格式（如 Unix 秒、Unix 毫秒或 ISO 8601），再渲染為目標格式和時區。大多數時間戳記問題源於時區和單位混淆。' },
    { id: 'q20', category: '資料格式', question: 'UUID 是什麼，什麼時候應該使用它？', answer: 'UUID 是可以在無需中央資料庫的情況下產生的全域唯一識別碼，適用於分散式系統、測試資料以及不應輕易被列舉的識別碼場景。' },
    { id: 'q21', category: '資料格式', question: 'JSON Schema 是什麼，為什麼要使用它？', answer: 'JSON Schema 定義了 JSON 文件允許的結構、型別和規則，有助於保持 API、事件和設定檔的一致性和可測試性。' },
    { id: 'q22', category: '資料格式', question: '如何比較兩個文字檔案的差異？', answer: '使用能並排顯示新增、刪除和修改內容的 diff 工具。這比手動掃描大型檔案更快、更安全。' },
    { id: 'q23', category: '網路與 Web', question: 'CIDR 子網路和 IP 範圍是如何運作的？', answer: 'CIDR 使用前綴長度將 IP 位址劃分為網路位元和主機位元。根據前綴可以計算出子網路遮罩、可用位址範圍、廣播位址和路由範圍。' },
    { id: 'q24', category: '網路與 Web', question: 'User-Agent 字串包含哪些資訊？', answer: 'User-Agent 字串通常包含瀏覽器系列、版本、渲染引擎、作業系統及裝置提示，但出於相容性考量，其中的資訊可能不完整甚至被刻意偽造。' },
    { id: 'q25', category: '網路與 Web', question: '如何使用 cURL 除錯 API？', answer: '從方法、URL、請求標頭和請求本文開始，然後加入 verbose 輸出以檢查請求和回應。cURL 非常適合將網路行為從應用程式碼中隔離出來單獨排查。' },
    { id: 'q26', category: '網路與 Web', question: 'SAML 是什麼，SSO 是如何運作的？', answer: 'SAML 是企業 SSO 中廣泛使用的基於 XML 的協議。身份提供者對使用者進行身份驗證，然後將已簽名的斷言傳送給服務提供者，使用者無需單獨輸入密碼即可存取應用程式。' },
    { id: 'q27', category: '網路與 Web', question: '電子郵件安全中的 SPF、DKIM 和 DMARC 是什麼？', answer: 'SPF 授權發送伺服器，DKIM 對郵件進行簽名，DMARC 告知接收方如何處理驗證失敗的郵件。三者配合使用可有效減少欺騙並提升郵件信任度。' },
    { id: 'q28', category: '開發者生產力', question: '如何估算 LLM 的 API token 費用？', answer: '估算提示詞 token 數、輸出 token 數以及供應商的計費標準，然後計算每次請求的費用和預期流量下的總成本。最關鍵的變數是模型選擇、上下文長度和回應大小。' },
    { id: 'q29', category: '開發者生產力', question: 'cron 表示式是什麼，如何編寫？', answer: 'cron 表示式是定義週期性任務排程的緊湊語法。逐欄位構建，在投入生產前務必驗證時區並預覽下次執行時間。' },
    { id: 'q30', category: '開發者生產力', question: '如何為 AI 建立有效的提示詞範本？', answer: '使用包含清晰指令、動態資料佔位符和明確輸出要求的穩定結構。好的提示詞範本應可複用、可測試，且足夠具體以減少歧義。' }
  ],
  fr: [
    { id: 'q1', category: 'Général', question: "Qu'est-ce que SimpleTool et à qui s'adresse-t-il ?", answer: "SimpleTool est une collection d'utilitaires pour navigateur axée sur la confidentialité, destinée aux développeurs, aux opérateurs et aux utilisateurs avancés. Les tâches comme le formatage JSON, le décodage de jetons ou la génération d'identifiants s'exécutent localement dans le navigateur, sans passer par nos serveurs." },
    { id: 'q2', category: 'Général', question: 'SimpleTool est-il vraiment gratuit ?', answer: "Oui. Les outils principaux du site public sont gratuits ; une partie des coûts d'hébergement et de maintenance est couverte par la publicité. Aucun abonnement payant n'est requis pour accéder aux fonctionnalités de base." },
    { id: 'q3', category: 'Général', question: 'Dois-je créer un compte ?', answer: "Non. Vous pouvez ouvrir un outil et l'utiliser immédiatement sans créer de compte ni vous connecter." },
    { id: 'q4', category: 'Général', question: 'Mes données sont-elles en sécurité ? Comment fonctionne le traitement côté client ?', answer: "Pour la plupart des outils, le traitement s'effectue localement dans votre navigateur à l'aide de JavaScript et des API du navigateur. Cela signifie que les données saisies restent généralement sur votre appareil, à moins que vous ne les copiez, exportiez ou envoyiez ailleurs." },
    { id: 'q5', category: 'Général', question: 'Quels navigateurs sont pris en charge ?', answer: "SimpleTool prend en charge les versions modernes de Chrome, Edge, Firefox et Safari, ainsi que les navigateurs mobiles récents. Les anciens navigateurs dépourvus de modules ES ou de Web Crypto peuvent ne pas fonctionner correctement." },
    { id: 'q6', category: 'Général', question: 'Puis-je utiliser SimpleTool hors ligne ?', answer: "De nombreux outils continuent de fonctionner après le chargement de la page, car la logique s'exécute côté client. Pour un flux de travail hors ligne fiable, l'hébergement personnel du projet est l'option la plus sûre." },
    { id: 'q7', category: 'Sécurité et cryptographie', question: 'Qu\'est-ce qui rend un mot de passe vraiment sécurisé ?', answer: "Un mot de passe sécurisé est long, aléatoire et unique par service. La longueur et l'imprévisibilité comptent plus que les substitutions astucieuses ou les schémas mémorisables." },
    { id: 'q8', category: 'Sécurité et cryptographie', question: 'Quelle est la différence entre MD5, SHA-256 et SHA-512 ?', answer: "MD5 est obsolète pour la sécurité. SHA-256 et SHA-512 sont des hachages SHA-2 modernes ; SHA-512 produit une empreinte plus longue, tandis que SHA-256 est le choix par défaut courant pour la vérification d'intégrité et les flux de signature." },
    { id: 'q9', category: 'Sécurité et cryptographie', question: 'Pourquoi MD5 est-il considéré comme cassé ?', answer: "MD5 est vulnérable aux attaques par collision pratiques : deux entrées différentes peuvent être conçues pour produire le même hachage. Il est donc inadapté à la confiance, aux signatures ou au stockage de mots de passe." },
    { id: 'q10', category: 'Sécurité et cryptographie', question: "Qu'est-ce que HMAC et quand l'utiliser ?", answer: "HMAC combine une fonction de hachage avec une clé secrète partagée. Utilisez-le quand vous avez besoin à la fois d'intégrité et d'authenticité, comme pour les requêtes API signées ou la vérification de webhooks." },
    { id: 'q11', category: 'Sécurité et cryptographie', question: 'Comment bcrypt se compare-t-il à Argon2 pour le hachage de mots de passe ?', answer: "Les deux sont des algorithmes conçus spécifiquement pour les mots de passe, mais Argon2 est le choix plus moderne car il est memory-hard et plus facile à paramétrer contre les attaques GPU. bcrypt reste courant pour des raisons de compatibilité." },
    { id: 'q12', category: 'Sécurité et cryptographie', question: "Qu'est-ce qu'un JWT et quand l'utiliser ?", answer: "Un JWT est un format de jeton compact pour transporter des claims entre systèmes. Il est utile pour l'authentification sans état et l'identité service-à-service, mais uniquement lorsque les signatures, l'expiration et la validation sont correctement gérées." },
    { id: 'q13', category: 'Sécurité et cryptographie', question: "Comment vérifier l'intégrité d'un fichier à l'aide de checksums ?", answer: "Calculez le hachage du fichier localement et comparez-le avec la valeur officielle fournie par l'éditeur. Si les hachages correspondent exactement, le fichier n'a très probablement pas été modifié." },
    { id: 'q14', category: 'Sécurité et cryptographie', question: "Qu'est-ce que la Content Security Policy (CSP) et pourquoi est-elle importante ?", answer: "La CSP est une politique de sécurité imposée par le navigateur qui restreint les sources autorisées pour les scripts, styles, images et autres ressources. C'est l'une des défenses les plus efficaces contre les attaques XSS et les injections de contenu." },
    { id: 'q15', category: 'Formats de données', question: 'Quelle est la différence entre JSON et YAML ?', answer: "JSON est plus strict, plus prévisible et généralement meilleur pour les API et les échanges machine à machine. YAML est plus lisible pour les humains, mais l'indentation et la syntaxe avancée peuvent introduire des erreurs cachées." },
    { id: 'q16', category: 'Formats de données', question: 'Comment valider du JSON ?', answer: "Vérifiez d'abord que la syntaxe est valide, puis validez la structure avec un schéma si les données doivent respecter un contrat. La validation syntaxique seule ne garantit pas les bons champs ni les bons types." },
    { id: 'q17', category: 'Formats de données', question: "Qu'est-ce que l'encodage Base64 et quand est-il utilisé ?", answer: "Base64 est un encodage qui transforme des données binaires en texte sûr. Il est couramment utilisé dans les jetons, les payloads d'e-mails, les data URL et les formats de transport qui exigent du texte brut." },
    { id: 'q18', category: 'Formats de données', question: 'Que sont les expressions régulières et pourquoi sont-elles utiles ?', answer: "Les expressions régulières sont des patterns compacts pour correspondre et transformer du texte. Elles sont utiles pour la validation, l'extraction, la recherche et le nettoyage, mais doivent être écrites avec soin pour éviter la complexité et les problèmes de performance." },
    { id: 'q19', category: 'Formats de données', question: 'Comment convertir entre différents formats de timestamp ?', answer: "Normalisez d'abord la source vers une référence claire comme Unix en secondes, Unix en millisecondes ou ISO 8601, puis affichez-la dans le format et le fuseau horaire cibles. La plupart des bugs de timestamp proviennent de confusions de fuseau horaire et d'unités." },
    { id: 'q20', category: 'Formats de données', question: "Qu'est-ce qu'un UUID et quand l'utiliser ?", answer: "Un UUID est un identifiant globalement unique qui peut être généré sans base de données centralisée. Il est utile pour les systèmes distribués, les données de test et les identifiants qui ne doivent pas être faciles à énumérer." },
    { id: 'q21', category: 'Formats de données', question: "Qu'est-ce que JSON Schema et pourquoi l'utiliser ?", answer: "JSON Schema définit la structure, les types et les règles autorisées pour les documents JSON. Il aide à maintenir la cohérence et la testabilité des API, événements et fichiers de configuration." },
    { id: 'q22', category: 'Formats de données', question: 'Comment comparer deux fichiers texte pour trouver les différences ?', answer: "Utilisez un outil de diff qui met en évidence les ajouts, suppressions et modifications côte à côte. C'est plus rapide et plus sûr que d'analyser manuellement de grands fichiers." },
    { id: 'q23', category: 'Réseau et Web', question: 'Comment fonctionnent les sous-réseaux CIDR et les plages IP ?', answer: "CIDR utilise une longueur de préfixe pour diviser une adresse IP en bits réseau et bits hôte. À partir de ce préfixe, vous pouvez calculer le masque de sous-réseau, la plage utilisable, l'adresse de diffusion et la portée de la route." },
    { id: 'q24', category: 'Réseau et Web', question: "Quelles informations contient une chaîne User-Agent ?", answer: "Une chaîne User-Agent expose généralement la famille du navigateur, la version, le moteur de rendu, le système d'exploitation et parfois des indices sur l'appareil. Elle est utile pour le débogage, mais peut être incomplète ou délibérément trompeuse." },
    { id: 'q25', category: 'Réseau et Web', question: "Comment utiliser cURL pour déboguer des API ?", answer: "Commencez avec la méthode, l'URL, les en-têtes et le corps, puis ajoutez la sortie verbose pour inspecter la requête et la réponse. cURL est idéal pour isoler le comportement réseau du code applicatif." },
    { id: 'q26', category: 'Réseau et Web', question: "Qu'est-ce que SAML et comment fonctionne le SSO ?", answer: "SAML est un protocole basé sur XML très utilisé dans le SSO d'entreprise. Un fournisseur d'identité authentifie l'utilisateur et envoie une assertion signée au fournisseur de services pour lui permettre d'accéder à l'application sans mot de passe séparé." },
    { id: 'q27', category: 'Réseau et Web', question: "Que sont SPF, DKIM et DMARC dans la sécurité des e-mails ?", answer: "SPF autorise les serveurs d'envoi, DKIM signe le message et DMARC indique aux récepteurs comment gérer les échecs. Ensemble, ils réduisent l'usurpation et améliorent la confiance dans le courrier entrant." },
    { id: 'q28', category: 'Productivité développeur', question: "Comment estimer les coûts en tokens d'API pour les LLM ?", answer: "Estimez les tokens du prompt, les tokens de sortie et le modèle de tarification de votre fournisseur, puis calculez le coût par requête et au volume attendu. Les variables les plus importantes sont le choix du modèle, la longueur du contexte et la taille de la réponse." },
    { id: 'q29', category: 'Productivité développeur', question: "Qu'est-ce qu'une expression cron et comment en écrire une ?", answer: "Une expression cron est une définition de planification compacte pour les tâches récurrentes. Construisez-la champ par champ, vérifiez le fuseau horaire et prévisualisez les prochaines exécutions avant de la mettre en production." },
    { id: 'q30', category: 'Productivité développeur', question: "Comment créer des templates de prompts efficaces pour l'IA ?", answer: "Utilisez une structure stable avec des instructions claires, des espaces réservés pour les données dynamiques et des exigences de sortie explicites. Les bons templates de prompts sont réutilisables, testables et suffisamment précis pour réduire l'ambiguïté." }
  ],
  de: [
    { id: 'q1', category: 'Allgemein', question: 'Was ist SimpleTool und für wen ist es gedacht?', answer: 'SimpleTool ist eine datenschutzorientierte Sammlung von Browser-Werkzeugen für Entwickler, Betreiber und Power-User. Aufgaben wie JSON-Formatierung, Token-Inspektion oder das Erzeugen von Zugangsdaten werden lokal im Browser ausgeführt, nicht auf unseren Servern.' },
    { id: 'q2', category: 'Allgemein', question: 'Ist SimpleTool wirklich kostenlos?', answer: 'Ja. Die Kernwerkzeuge der öffentlichen Seite sind kostenlos nutzbar; ein Teil der Hosting- und Wartungskosten wird durch Werbung gedeckt. Es gibt keine kostenpflichtigen Stufen für den Zugang zu den Basisfunktionen.' },
    { id: 'q3', category: 'Allgemein', question: 'Muss ich ein Konto erstellen?', answer: 'Nein. Sie können ein Werkzeug öffnen und es sofort verwenden, ohne sich zu registrieren oder anzumelden.' },
    { id: 'q4', category: 'Allgemein', question: 'Sind meine Daten sicher? Wie funktioniert die clientseitige Verarbeitung?', answer: 'Bei den meisten Werkzeugen erfolgt die Verarbeitung lokal in Ihrem Browser mithilfe von JavaScript und Browser-APIs. Das bedeutet, dass Ihre Eingaben in der Regel auf Ihrem Gerät bleiben, sofern Sie sie nicht explizit kopieren, exportieren oder anderswo hinschicken.' },
    { id: 'q5', category: 'Allgemein', question: 'Welche Browser werden unterstützt?', answer: 'SimpleTool unterstützt aktuelle Versionen von Chrome, Edge, Firefox und Safari sowie aktuelle mobile Browser. Ältere Browser ohne ES-Modul- oder Web-Crypto-Unterstützung funktionieren möglicherweise nicht korrekt.' },
    { id: 'q6', category: 'Allgemein', question: 'Kann ich SimpleTool offline nutzen?', answer: 'Viele Werkzeuge funktionieren nach dem ersten Laden auch ohne Internetverbindung, da die Logik clientseitig ausgeführt wird. Für einen zuverlässigen Offline-Workflow empfiehlt sich das Selbst-Hosten des Projekts.' },
    { id: 'q7', category: 'Sicherheit und Kryptographie', question: 'Was macht ein Passwort wirklich sicher?', answer: 'Ein sicheres Passwort ist lang, zufällig und für jeden Dienst eindeutig. Länge und Unvorhersehbarkeit sind wichtiger als clevere Ersetzungen oder einprägsame Muster.' },
    { id: 'q8', category: 'Sicherheit und Kryptographie', question: 'Was ist der Unterschied zwischen MD5, SHA-256 und SHA-512?', answer: 'MD5 ist für Sicherheitszwecke veraltet. SHA-256 und SHA-512 sind moderne SHA-2-Hashfunktionen; SHA-512 hat eine längere Ausgabe, während SHA-256 der gängige Standard für Integritätsprüfungen und Signaturworkflows ist.' },
    { id: 'q9', category: 'Sicherheit und Kryptographie', question: 'Warum gilt MD5 als gebrochen?', answer: 'MD5 ist anfällig für praktische Kollisionsangriffe, bei denen zwei unterschiedliche Eingaben den gleichen Hash erzeugen können. Daher ist es ungeeignet für Vertrauensprüfungen, Signaturen oder die Passwort-Speicherung.' },
    { id: 'q10', category: 'Sicherheit und Kryptographie', question: 'Was ist HMAC und wann sollte ich es verwenden?', answer: 'HMAC kombiniert eine Hashfunktion mit einem gemeinsamen geheimen Schlüssel. Verwenden Sie es, wenn Sie sowohl Integrität als auch Authentizität benötigen, beispielsweise bei signierten API-Anfragen oder der Webhook-Verifizierung.' },
    { id: 'q11', category: 'Sicherheit und Kryptographie', question: 'Wie schneidet bcrypt im Vergleich zu Argon2 beim Passwort-Hashing ab?', answer: 'Beide sind speziell für das Passwort-Hashing entwickelte Algorithmen, aber Argon2 ist die modernere Wahl, da es speicherintensiv ist und sich leichter gegen GPU-Angriffe absichern lässt. bcrypt bleibt aus Kompatibilitätsgründen weit verbreitet.' },
    { id: 'q12', category: 'Sicherheit und Kryptographie', question: 'Was ist ein JWT und wann sollte ich es verwenden?', answer: 'Ein JWT ist ein kompaktes Token-Format zum Übertragen von Claims zwischen Systemen. Es eignet sich für zustandslose Authentifizierung und Service-to-Service-Identität, sofern Signaturen, Ablaufzeiten und Validierung korrekt implementiert sind.' },
    { id: 'q13', category: 'Sicherheit und Kryptographie', question: 'Wie überprüfe ich die Integrität einer Datei mithilfe von Hash-Prüfsummen?', answer: 'Berechnen Sie den Hash der Datei lokal und vergleichen Sie ihn mit dem offiziellen Wert des Herausgebers. Stimmen die Hashes exakt überein, ist die Datei höchstwahrscheinlich unverändert.' },
    { id: 'q14', category: 'Sicherheit und Kryptographie', question: 'Was ist Content Security Policy (CSP) und warum ist sie wichtig?', answer: 'CSP ist eine vom Browser durchgesetzte Sicherheitsrichtlinie, die einschränkt, woher Skripte, Styles, Bilder und andere Ressourcen geladen werden dürfen. Sie ist eine der wirksamsten Abwehrmaßnahmen gegen XSS und eingeschleusten Content.' },
    { id: 'q15', category: 'Datenformate', question: 'Was ist der Unterschied zwischen JSON und YAML?', answer: 'JSON ist strenger und vorhersehbarer und eignet sich besser für APIs und den maschinellen Datenaustausch. YAML ist für Menschen leichter lesbar, aber Einrückungen und erweiterte Syntax können versteckte Fehler verursachen.' },
    { id: 'q16', category: 'Datenformate', question: 'Wie validiere ich JSON?', answer: 'Prüfen Sie zunächst die Syntax, und validieren Sie dann die Struktur gegen ein Schema, wenn die Daten einem Vertrag entsprechen müssen. Die reine Syntaxvalidierung stellt keine korrekten Felder oder Typen sicher.' },
    { id: 'q17', category: 'Datenformate', question: 'Was ist Base64-Kodierung und wann wird sie verwendet?', answer: 'Base64 ist eine textsichere Kodierung für Binärdaten. Sie wird häufig in Tokens, E-Mail-Payloads, Data-URLs und Transportformaten verwendet, die reinen Text erfordern.' },
    { id: 'q18', category: 'Datenformate', question: 'Was sind reguläre Ausdrücke und warum sind sie nützlich?', answer: 'Reguläre Ausdrücke sind kompakte Muster zum Suchen und Transformieren von Text. Sie sind nützlich für Validierung, Extraktion, Suche und Bereinigung, sollten aber sorgfältig geschrieben werden, um Komplexität und Leistungsprobleme zu vermeiden.' },
    { id: 'q19', category: 'Datenformate', question: 'Wie konvertiere ich zwischen verschiedenen Timestamp-Formaten?', answer: 'Normalisieren Sie die Quelle zunächst in ein klares Referenzformat wie Unix-Sekunden, Unix-Millisekunden oder ISO 8601 und rendern Sie es dann im Zielformat und der Ziel-Zeitzone. Die meisten Timestamp-Fehler entstehen durch Verwechslungen von Zeitzone und Einheit.' },
    { id: 'q20', category: 'Datenformate', question: 'Was ist eine UUID und wann sollte ich sie verwenden?', answer: 'Eine UUID ist ein global eindeutiger Bezeichner, der ohne zentrale Datenbank generiert werden kann. Er ist nützlich für verteilte Systeme, Testdaten und Bezeichner, die nicht leicht aufgezählt werden sollen.' },
    { id: 'q21', category: 'Datenformate', question: 'Was ist JSON Schema und warum sollte ich es verwenden?', answer: 'JSON Schema definiert die erlaubte Struktur, Typen und Regeln für JSON-Dokumente. Es hilft dabei, APIs, Ereignisse und Konfigurationsdateien konsistent und testbar zu halten.' },
    { id: 'q22', category: 'Datenformate', question: 'Wie vergleiche ich zwei Textdateien auf Unterschiede?', answer: 'Verwenden Sie ein Diff-Werkzeug, das hinzugefügte, gelöschte und geänderte Abschnitte nebeneinander hervorhebt. Das ist schneller und sicherer als das manuelle Durchsuchen großer Dateien.' },
    { id: 'q23', category: 'Netzwerk und Web', question: 'Wie funktionieren CIDR-Subnetze und IP-Bereiche?', answer: 'CIDR verwendet eine Präfixlänge, um eine IP-Adresse in Netzwerk- und Host-Bits aufzuteilen. Aus diesem Präfix lassen sich Subnetzmaske, nutzbarer Bereich, Broadcast-Adresse und Routenumfang berechnen.' },
    { id: 'q24', category: 'Netzwerk und Web', question: 'Welche Informationen enthält ein User-Agent-String?', answer: 'Ein User-Agent-String enthält in der Regel die Browser-Familie, Version, Rendering-Engine, Betriebssystem und manchmal Gerätehinweise. Er ist zum Debuggen nützlich, kann aber unvollständig oder absichtlich irreführend sein.' },
    { id: 'q25', category: 'Netzwerk und Web', question: 'Wie verwende ich cURL zum Debuggen von APIs?', answer: 'Beginnen Sie mit Methode, URL, Headern und Body und fügen Sie dann die verbose Ausgabe hinzu, um Anfrage und Antwort zu inspizieren. cURL eignet sich ideal, um das Netzwerkverhalten vom Anwendungscode zu isolieren.' },
    { id: 'q26', category: 'Netzwerk und Web', question: 'Was ist SAML und wie funktioniert SSO?', answer: 'SAML ist ein XML-basiertes Protokoll, das in Enterprise-SSO weit verbreitet ist. Ein Identity Provider authentifiziert den Benutzer und sendet eine signierte Assertion an den Service Provider, sodass der Benutzer ohne separates Passwort auf die App zugreifen kann.' },
    { id: 'q27', category: 'Netzwerk und Web', question: 'Was sind SPF, DKIM und DMARC in der E-Mail-Sicherheit?', answer: 'SPF autorisiert sendende Server, DKIM signiert die Nachricht und DMARC legt fest, wie Empfänger mit Fehlschlägen umgehen sollen. Zusammen reduzieren sie Spoofing und verbessern das Vertrauen in eingehende E-Mails.' },
    { id: 'q28', category: 'Entwicklerproduktivität', question: 'Wie schätze ich API-Token-Kosten für LLMs?', answer: 'Schätzen Sie die Prompt-Tokens, Output-Tokens und das Preismodell Ihres Anbieters, und berechnen Sie dann die Kosten pro Anfrage und beim erwarteten Volumen. Die wichtigsten Variablen sind Modellwahl, Kontextlänge und Antwortgröße.' },
    { id: 'q29', category: 'Entwicklerproduktivität', question: 'Was ist ein Cron-Ausdruck und wie schreibt man einen?', answer: 'Ein Cron-Ausdruck ist eine kompakte Zeitplandefinition für wiederkehrende Jobs. Bauen Sie ihn Feld für Feld auf, überprüfen Sie die Zeitzone und zeigen Sie die nächsten Ausführungszeiten in der Vorschau an, bevor Sie ihn in Produktion nehmen.' },
    { id: 'q30', category: 'Entwicklerproduktivität', question: 'Wie erstelle ich effektive Prompt-Templates für KI?', answer: 'Verwenden Sie eine stabile Struktur mit klaren Anweisungen, Platzhaltern für dynamische Daten und expliziten Ausgabeanforderungen. Gute Prompt-Templates sind wiederverwendbar, testbar und präzise genug, um Mehrdeutigkeiten zu reduzieren.' }
  ],
  pt: [
    { id: 'q1', category: 'Geral', question: 'O que é o SimpleTool e para quem é indicado?', answer: 'SimpleTool é uma coleção de utilitários para navegador com foco em privacidade, voltada para desenvolvedores, operadores e usuários avançados. Tarefas como formatar JSON, decodificar tokens ou gerar credenciais são executadas localmente no navegador, não nos nossos servidores.' },
    { id: 'q2', category: 'Geral', question: 'O SimpleTool é realmente gratuito?', answer: 'Sim. As ferramentas principais do site público são gratuitas; parte dos custos de hospedagem e manutenção é coberta por publicidade. Não há planos pagos necessários para acessar as ferramentas principais.' },
    { id: 'q3', category: 'Geral', question: 'Preciso criar uma conta?', answer: 'Não. Você pode abrir uma ferramenta e usá-la imediatamente sem criar conta ou fazer login.' },
    { id: 'q4', category: 'Geral', question: 'Meus dados estão seguros? Como funciona o processamento no lado do cliente?', answer: 'Na maioria das ferramentas, o processamento acontece localmente no navegador usando JavaScript e APIs do navegador. Isso significa que os dados inseridos geralmente ficam no seu dispositivo, a menos que você os copie, exporte ou envie explicitamente para outro lugar.' },
    { id: 'q5', category: 'Geral', question: 'Quais navegadores são suportados?', answer: 'O SimpleTool suporta versões modernas de Chrome, Edge, Firefox e Safari, além de navegadores móveis atualizados. Navegadores antigos sem suporte a módulos ES ou Web Crypto podem não funcionar corretamente.' },
    { id: 'q6', category: 'Geral', question: 'Posso usar o SimpleTool offline?', answer: 'Muitas ferramentas continuam funcionando após o carregamento da página, pois a lógica é executada no lado do cliente. Para um fluxo de trabalho offline confiável, hospedar o projeto por conta própria é a opção mais segura.' },
    { id: 'q7', category: 'Segurança e Criptografia', question: 'O que torna uma senha verdadeiramente segura?', answer: 'Uma senha segura é longa, aleatória e única por serviço. Comprimento e imprevisibilidade importam mais do que substituições inteligentes ou padrões memoráveis.' },
    { id: 'q8', category: 'Segurança e Criptografia', question: 'Qual é a diferença entre MD5, SHA-256 e SHA-512?', answer: 'MD5 é obsoleto para fins de segurança. SHA-256 e SHA-512 são hashes modernos SHA-2; SHA-512 tem uma saída maior, enquanto SHA-256 é o padrão comum para verificação de integridade e fluxos de assinatura.' },
    { id: 'q9', category: 'Segurança e Criptografia', question: 'Por que o MD5 é considerado quebrado?', answer: 'O MD5 é vulnerável a ataques de colisão práticos, onde duas entradas diferentes podem ser criadas para produzir o mesmo hash. Isso o torna inadequado para confiança, assinaturas ou armazenamento de senhas.' },
    { id: 'q10', category: 'Segurança e Criptografia', question: 'O que é HMAC e quando devo usá-lo?', answer: 'HMAC combina uma função hash com uma chave secreta compartilhada. Use-o quando precisar tanto de integridade quanto de autenticidade, como em requisições de API assinadas ou verificação de webhooks.' },
    { id: 'q11', category: 'Segurança e Criptografia', question: 'Como o bcrypt se compara ao Argon2 para hashing de senhas?', answer: 'Ambos são algoritmos criados especificamente para hashing de senhas, mas o Argon2 é a escolha mais moderna por ser memory-hard e mais fácil de ajustar contra ataques de GPU. O bcrypt ainda é comum por questões de compatibilidade.' },
    { id: 'q12', category: 'Segurança e Criptografia', question: 'O que é um JWT e quando devo usá-lo?', answer: 'Um JWT é um formato de token compacto para transportar claims entre sistemas. É útil para autenticação sem estado e identidade serviço a serviço, mas apenas quando assinaturas, expiração e validação são tratadas corretamente.' },
    { id: 'q13', category: 'Segurança e Criptografia', question: 'Como verifico a integridade de um arquivo usando checksums hash?', answer: 'Calcule o hash do arquivo localmente e compare com o valor oficial fornecido pelo publicador. Se os hashes corresponderem exatamente, é muito provável que o arquivo não tenha sido alterado.' },
    { id: 'q14', category: 'Segurança e Criptografia', question: 'O que é Content Security Policy (CSP) e por que ela importa?', answer: 'CSP é uma política de segurança aplicada pelo navegador que restringe de onde scripts, estilos, imagens e outros recursos podem ser carregados. É uma das defesas mais fortes contra XSS e conteúdo injetado.' },
    { id: 'q15', category: 'Formatos de Dados', question: 'Qual é a diferença entre JSON e YAML?', answer: 'JSON é mais estrito, mais previsível e geralmente melhor para APIs e troca entre máquinas. YAML é mais fácil para humanos editarem, mas indentação e sintaxe avançada podem introduzir erros ocultos.' },
    { id: 'q16', category: 'Formatos de Dados', question: 'Como valido JSON?', answer: 'Primeiro verifique se a sintaxe é válida, depois valide a estrutura contra um schema se os dados precisam seguir um contrato. A validação de sintaxe sozinha não garante os campos ou tipos corretos.' },
    { id: 'q17', category: 'Formatos de Dados', question: 'O que é codificação Base64 e quando é usada?', answer: 'Base64 é uma codificação segura para texto de dados binários. É comumente usada em tokens, payloads de e-mail, data URLs e formatos de transporte que requerem texto simples.' },
    { id: 'q18', category: 'Formatos de Dados', question: 'O que são expressões regulares e por que são úteis?', answer: 'Expressões regulares são padrões compactos para combinar e transformar texto. São úteis para validação, extração, busca e limpeza, mas devem ser escritas com cuidado para evitar complexidade e problemas de desempenho.' },
    { id: 'q19', category: 'Formatos de Dados', question: 'Como converter entre diferentes formatos de timestamp?', answer: 'Normalize a fonte para uma referência clara como Unix em segundos, Unix em milissegundos ou ISO 8601, depois renderize no formato e fuso horário alvo. A maioria dos bugs de timestamp vem de incompatibilidades de fuso horário e unidade.' },
    { id: 'q20', category: 'Formatos de Dados', question: 'O que é um UUID e quando devo usá-lo?', answer: 'Um UUID é um identificador globalmente único que pode ser gerado sem um banco de dados central. É útil para sistemas distribuídos, dados de teste e identificadores que não devem ser fáceis de enumerar.' },
    { id: 'q21', category: 'Formatos de Dados', question: 'O que é JSON Schema e por que devo usá-lo?', answer: 'JSON Schema define a estrutura, tipos e regras permitidos para documentos JSON. Ajuda a manter APIs, eventos e arquivos de configuração consistentes e testáveis.' },
    { id: 'q22', category: 'Formatos de Dados', question: 'Como comparo dois arquivos de texto para encontrar diferenças?', answer: 'Use uma ferramenta de diff que destaque seções adicionadas, removidas e alteradas lado a lado. É mais rápido e seguro do que verificar manualmente arquivos grandes.' },
    { id: 'q23', category: 'Redes e Web', question: 'Como funcionam sub-redes CIDR e intervalos de IP?', answer: 'CIDR usa um comprimento de prefixo para dividir um endereço IP em bits de rede e de host. A partir desse prefixo você pode calcular a máscara de sub-rede, o intervalo utilizável, o endereço de broadcast e o escopo da rota.' },
    { id: 'q24', category: 'Redes e Web', question: 'Que informações uma string User-Agent contém?', answer: 'Uma string User-Agent geralmente expõe a família do navegador, versão, motor de renderização, sistema operacional e às vezes dicas de dispositivo. É útil para depuração, mas pode ser incompleta ou intencionalmente enganosa.' },
    { id: 'q25', category: 'Redes e Web', question: 'Como usar cURL para depurar APIs?', answer: 'Comece com o método, URL, cabeçalhos e corpo, depois adicione saída verbose para inspecionar a requisição e a resposta. O cURL é ideal para isolar o comportamento de rede do código da aplicação.' },
    { id: 'q26', category: 'Redes e Web', question: 'O que é SAML e como funciona o SSO?', answer: 'SAML é um protocolo baseado em XML muito usado em SSO empresarial. Um provedor de identidade autentica o usuário e envia uma assertion assinada ao provedor de serviço para que o usuário acesse o app sem uma senha separada.' },
    { id: 'q27', category: 'Redes e Web', question: 'O que são SPF, DKIM e DMARC na segurança de e-mail?', answer: 'SPF autoriza servidores de envio, DKIM assina a mensagem e DMARC informa aos receptores como lidar com falhas. Juntos reduzem spoofing e melhoram a confiança no e-mail recebido.' },
    { id: 'q28', category: 'Produtividade do Desenvolvedor', question: 'Como estimo os custos de tokens de API para LLMs?', answer: 'Estime os tokens de prompt, tokens de saída e o modelo de preços do seu provedor, depois calcule o custo por requisição e no volume esperado. As variáveis mais importantes são a escolha do modelo, o comprimento do contexto e o tamanho da resposta.' },
    { id: 'q29', category: 'Produtividade do Desenvolvedor', question: 'O que é uma expressão cron e como escrever uma?', answer: 'Uma expressão cron é uma definição de agenda compacta para jobs recorrentes. Construa campo por campo, verifique o fuso horário e visualize os próximos horários de execução antes de colocar em produção.' },
    { id: 'q30', category: 'Produtividade do Desenvolvedor', question: 'Como criar templates de prompt eficazes para IA?', answer: 'Use uma estrutura estável com instruções claras, marcadores para dados dinâmicos e requisitos de saída explícitos. Bons templates de prompt são reutilizáveis, testáveis e precisos o suficiente para reduzir ambiguidade.' }
  ],
  vi: [
    { id: 'q1', category: 'Chung', question: 'SimpleTool là gì và dành cho ai?', answer: 'SimpleTool là bộ công cụ trình duyệt ưu tiên bảo mật, dành cho các nhà phát triển, người vận hành và người dùng nâng cao. Các tác vụ như định dạng JSON, giải mã token hay tạo thông tin xác thực đều chạy trực tiếp trong trình duyệt mà không qua máy chủ của chúng tôi.' },
    { id: 'q2', category: 'Chung', question: 'SimpleTool có thực sự miễn phí không?', answer: 'Có. Các công cụ cốt lõi trên trang công cộng hoàn toàn miễn phí; một phần chi phí vận hành và bảo trì được trang trải bằng quảng cáo. Không cần gói trả phí để sử dụng các công cụ chính.' },
    { id: 'q3', category: 'Chung', question: 'Tôi có cần tạo tài khoản không?', answer: 'Không. Bạn có thể mở công cụ và dùng ngay lập tức mà không cần đăng ký hay đăng nhập.' },
    { id: 'q4', category: 'Chung', question: 'Dữ liệu của tôi có an toàn không? Xử lý phía máy khách hoạt động như thế nào?', answer: 'Hầu hết các công cụ đều xử lý dữ liệu cục bộ trong trình duyệt của bạn bằng JavaScript và các API trình duyệt. Điều đó có nghĩa là dữ liệu đầu vào thường ở lại trên thiết bị của bạn, trừ khi bạn chủ động sao chép, xuất hoặc gửi đến nơi khác.' },
    { id: 'q5', category: 'Chung', question: 'Trình duyệt nào được hỗ trợ?', answer: 'SimpleTool hỗ trợ các phiên bản hiện đại của Chrome, Edge, Firefox và Safari, cùng với các trình duyệt di động cập nhật. Các trình duyệt cũ không hỗ trợ ES modules hoặc Web Crypto có thể không hoạt động đúng cách.' },
    { id: 'q6', category: 'Chung', question: 'Tôi có thể dùng SimpleTool ngoại tuyến không?', answer: 'Nhiều công cụ tiếp tục hoạt động sau khi trang được tải vì logic chạy phía máy khách. Để có quy trình ngoại tuyến ổn định, tự host dự án là lựa chọn an toàn nhất.' },
    { id: 'q7', category: 'Bảo mật & Mật mã', question: 'Điều gì làm cho một mật khẩu thực sự an toàn?', answer: 'Mật khẩu an toàn phải đủ dài, ngẫu nhiên và duy nhất cho mỗi dịch vụ. Độ dài và tính khó đoán quan trọng hơn các ký tự thay thế khéo léo hay các mẫu dễ nhớ.' },
    { id: 'q8', category: 'Bảo mật & Mật mã', question: 'Sự khác biệt giữa MD5, SHA-256 và SHA-512 là gì?', answer: 'MD5 đã lỗi thời cho mục đích bảo mật. SHA-256 và SHA-512 là các hàm băm SHA-2 hiện đại; SHA-512 có đầu ra dài hơn, trong khi SHA-256 là lựa chọn mặc định phổ biến cho kiểm tra tính toàn vẹn và quy trình ký số.' },
    { id: 'q9', category: 'Bảo mật & Mật mã', question: 'Tại sao MD5 được coi là đã bị phá vỡ?', answer: 'MD5 dễ bị tấn công va chạm thực tế, cho phép tạo ra hai đầu vào khác nhau tạo ra cùng một giá trị băm. Điều này khiến nó không phù hợp cho xác thực tin cậy, chữ ký số hay lưu trữ mật khẩu.' },
    { id: 'q10', category: 'Bảo mật & Mật mã', question: 'HMAC là gì và khi nào nên sử dụng nó?', answer: 'HMAC kết hợp hàm băm với khóa bí mật dùng chung. Sử dụng khi bạn cần cả tính toàn vẹn lẫn tính xác thực, chẳng hạn như các yêu cầu API có chữ ký hoặc xác minh webhook.' },
    { id: 'q11', category: 'Bảo mật & Mật mã', question: 'bcrypt so sánh với Argon2 như thế nào trong việc băm mật khẩu?', answer: 'Cả hai đều là thuật toán chuyên dụng để băm mật khẩu, nhưng Argon2 là lựa chọn hiện đại hơn vì nó memory-hard và dễ điều chỉnh chống lại các cuộc tấn công GPU. bcrypt vẫn phổ biến vì lý do tương thích.' },
    { id: 'q12', category: 'Bảo mật & Mật mã', question: 'JWT là gì và khi nào nên sử dụng?', answer: 'JWT là định dạng token nhỏ gọn để mang các claim giữa các hệ thống. Nó hữu ích cho xác thực không trạng thái và nhận diện dịch vụ-sang-dịch vụ, nhưng chỉ khi chữ ký, thời hạn và xác thực được xử lý đúng cách.' },
    { id: 'q13', category: 'Bảo mật & Mật mã', question: 'Làm cách nào xác minh tính toàn vẹn của tệp bằng checksum băm?', answer: 'Tính toán hàm băm của tệp cục bộ và so sánh với giá trị chính thức từ nhà phát hành. Nếu các giá trị băm khớp chính xác, rất có thể tệp chưa bị thay đổi.' },
    { id: 'q14', category: 'Bảo mật & Mật mã', question: 'Content Security Policy (CSP) là gì và tại sao quan trọng?', answer: 'CSP là chính sách bảo mật do trình duyệt thực thi, giới hạn nơi các script, style, hình ảnh và các tài nguyên khác có thể được tải từ đó. Đây là một trong những biện pháp phòng thủ mạnh nhất chống lại XSS và nội dung bị chèn.' },
    { id: 'q15', category: 'Định dạng Dữ liệu', question: 'Sự khác biệt giữa JSON và YAML là gì?', answer: 'JSON nghiêm ngặt hơn, dễ đoán hơn và thường tốt hơn cho API và trao đổi máy-máy. YAML dễ đọc hơn cho con người, nhưng thụt lề và cú pháp nâng cao có thể gây ra lỗi ẩn.' },
    { id: 'q16', category: 'Định dạng Dữ liệu', question: 'Làm cách nào để kiểm tra tính hợp lệ của JSON?', answer: 'Trước tiên kiểm tra cú pháp có hợp lệ không, sau đó xác thực cấu trúc theo schema nếu dữ liệu phải tuân theo một hợp đồng. Chỉ kiểm tra cú pháp không đảm bảo các trường hay kiểu dữ liệu đúng.' },
    { id: 'q17', category: 'Định dạng Dữ liệu', question: 'Mã hóa Base64 là gì và khi nào được sử dụng?', answer: 'Base64 là mã hóa an toàn cho văn bản của dữ liệu nhị phân. Nó thường được dùng trong token, payload email, data URL và các định dạng truyền tải yêu cầu văn bản thuần túy.' },
    { id: 'q18', category: 'Định dạng Dữ liệu', question: 'Biểu thức chính quy là gì và tại sao hữu ích?', answer: 'Biểu thức chính quy là các mẫu nhỏ gọn để khớp và biến đổi văn bản. Chúng hữu ích cho xác thực, trích xuất, tìm kiếm và làm sạch dữ liệu, nhưng cần viết cẩn thận để tránh phức tạp và vấn đề hiệu suất.' },
    { id: 'q19', category: 'Định dạng Dữ liệu', question: 'Làm cách nào chuyển đổi giữa các định dạng timestamp khác nhau?', answer: 'Chuẩn hóa nguồn thành định dạng tham chiếu rõ ràng như Unix giây, Unix mili giây hoặc ISO 8601, sau đó hiển thị theo định dạng và múi giờ đích. Hầu hết lỗi timestamp xuất phát từ sự nhầm lẫn về múi giờ và đơn vị.' },
    { id: 'q20', category: 'Định dạng Dữ liệu', question: 'UUID là gì và khi nào nên sử dụng?', answer: 'UUID là định danh duy nhất toàn cầu có thể được tạo mà không cần cơ sở dữ liệu trung tâm. Nó hữu ích cho các hệ thống phân tán, dữ liệu thử nghiệm và các định danh không nên dễ dàng liệt kê.' },
    { id: 'q21', category: 'Định dạng Dữ liệu', question: 'JSON Schema là gì và tại sao nên sử dụng?', answer: 'JSON Schema định nghĩa cấu trúc, kiểu dữ liệu và quy tắc được phép cho tài liệu JSON. Nó giúp duy trì tính nhất quán và khả năng kiểm tra cho API, sự kiện và tệp cấu hình.' },
    { id: 'q22', category: 'Định dạng Dữ liệu', question: 'Làm cách nào so sánh sự khác biệt giữa hai tệp văn bản?', answer: 'Sử dụng công cụ diff hiển thị các phần thêm, xóa và thay đổi song song. Điều này nhanh hơn và an toàn hơn so với việc quét thủ công các tệp lớn.' },
    { id: 'q23', category: 'Mạng & Web', question: 'Mạng con CIDR và dải IP hoạt động như thế nào?', answer: 'CIDR sử dụng độ dài tiền tố để chia địa chỉ IP thành các bit mạng và bit máy chủ. Từ tiền tố đó bạn có thể tính mặt nạ mạng con, dải sử dụng được, địa chỉ broadcast và phạm vi định tuyến.' },
    { id: 'q24', category: 'Mạng & Web', question: 'Chuỗi User-Agent chứa thông tin gì?', answer: 'Chuỗi User-Agent thường tiết lộ họ trình duyệt, phiên bản, engine hiển thị, hệ điều hành và đôi khi gợi ý về thiết bị. Nó hữu ích để gỡ lỗi nhưng có thể không đầy đủ hoặc cố tình gây hiểu lầm.' },
    { id: 'q25', category: 'Mạng & Web', question: 'Làm cách nào dùng cURL để gỡ lỗi API?', answer: 'Bắt đầu với phương thức, URL, header và body, sau đó thêm đầu ra verbose để kiểm tra yêu cầu và phản hồi. cURL lý tưởng để cô lập hành vi mạng khỏi mã ứng dụng.' },
    { id: 'q26', category: 'Mạng & Web', question: 'SAML là gì và SSO hoạt động như thế nào?', answer: 'SAML là giao thức dựa trên XML được sử dụng rộng rãi trong SSO doanh nghiệp. Nhà cung cấp danh tính xác thực người dùng và gửi một assertion đã ký đến nhà cung cấp dịch vụ để người dùng truy cập ứng dụng mà không cần mật khẩu riêng.' },
    { id: 'q27', category: 'Mạng & Web', question: 'SPF, DKIM và DMARC trong bảo mật email là gì?', answer: 'SPF ủy quyền máy chủ gửi, DKIM ký thư và DMARC cho biết người nhận cách xử lý khi thất bại. Kết hợp lại chúng giảm giả mạo và cải thiện độ tin cậy của thư đến.' },
    { id: 'q28', category: 'Năng suất Lập trình viên', question: 'Làm cách nào ước tính chi phí token API cho LLM?', answer: 'Ước tính số token prompt, token đầu ra và mô hình định giá của nhà cung cấp, sau đó tính chi phí mỗi yêu cầu và ở lưu lượng dự kiến. Các biến quan trọng nhất là lựa chọn mô hình, độ dài ngữ cảnh và kích thước phản hồi.' },
    { id: 'q29', category: 'Năng suất Lập trình viên', question: 'Biểu thức cron là gì và cách viết?', answer: 'Biểu thức cron là định nghĩa lịch trình nhỏ gọn cho các công việc định kỳ. Xây dựng từng trường một, xác minh múi giờ và xem trước các lần chạy tiếp theo trước khi đưa vào môi trường sản xuất.' },
    { id: 'q30', category: 'Năng suất Lập trình viên', question: 'Làm cách nào tạo template prompt hiệu quả cho AI?', answer: 'Sử dụng cấu trúc ổn định với hướng dẫn rõ ràng, chỗ giữ chỗ cho dữ liệu động và yêu cầu đầu ra rõ ràng. Template prompt tốt có thể tái sử dụng, có thể kiểm tra và đủ cụ thể để giảm thiểu sự mơ hồ.' }
  ]
};

export function getFaqEntries(lang = DEFAULT_LANGUAGE) {
  const currentLang = normalizeLanguage(lang);
  return FAQ_CONTENT[currentLang] || FAQ_CONTENT[DEFAULT_LANGUAGE] || FAQ_CONTENT.en;
}
